1	.modal-overlay {
2	  position: fixed;
3	  inset: 0;
4	  background: rgba(0, 0, 0, 0.5);
5	  display: flex;
6	  align-items: center;
7	  justify-content: center;
8	  z-index: 100;
9	  backdrop-filter: blur(4px);
10	  -webkit-backdrop-filter: blur(4px);
11	  animation: modal-fade-in 150ms ease;
12	}
13	
14	@keyframes modal-fade-in {
15	  from { opacity: 0; }
16	  to   { opacity: 1; }
17	}
18	
19	.modal-content {
20	  background: #fff;
21	  border-radius: 8px;
22	  padding: 1.5rem;
23	  max-width: 480px;
24	  width: 90%;
25	  position: relative;
26	  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
27	  animation: modal-slide-in 150ms ease;
28	  max-height: 90vh;
29	  overflow-y: auto;
30	}
31	
32	@keyframes modal-slide-in {
33	  from { transform: translateY(12px); }
34	  to   { transform: translateY(0); }
35	}
36	
37	.modal-close {
38	  position: absolute;
39	  top: 0.75rem;
40	  right: 0.75rem;
41	  background: none;
42	  border: none;
43	  cursor: pointer;
44	  font-size: 1.1rem;
45	  color: #666;
46	}
47	
48	.modal-close:hover {
49	  color: #1a1a2e;
50	}
51	
52	.modal-title {
53	  font-size: 1.2rem;
54	  font-weight: 700;
55	  margin-bottom: 0.75rem;
56	  color: #1a1a2e;
57	}
58	
59	.modal-assignee {
60	  font-size: 0.875rem;
61	  color: #555;
62	  margin-bottom: 0.5rem;
63	}
64	
65	.modal-description {
66	  font-size: 0.875rem;
67	  color: #333;
68	  line-height: 1.5;
69	  margin-bottom: 0.5rem;
70	}
71	
72	/* Editable fields */
73	.modal-field-view {
74	  display: flex;
75	  align-items: center;
76	  gap: 0.5rem;
77	  margin-bottom: 0.5rem;
78	}
79	
80	.modal-field-edit {
81	  display: flex;
82	  align-items: center;
83	  gap: 0.5rem;
84	  flex-wrap: wrap;
85	  margin-bottom: 0.5rem;
86	}
87	
88	.modal-field-edit input {
89	  flex: 1;
90	  padding: 0.25rem 0.5rem;
91	  font-size: 0.875rem;
92	  border: 1px solid #ccc;
93	  border-radius: 4px;
94	}
95	
96	/* Error alert */
97	.modal-error {
98	  color: #c0392b;
99	  font-size: 0.8rem;
100	  margin: 0.25rem 0;
101	}
102	
103	/* Delete */
104	.modal-delete {
105	  margin-top: 1rem;
106	  background: none;
107	  border: 1px solid #c0392b;
108	  color: #c0392b;
109	  padding: 0.3rem 0.75rem;
110	  border-radius: 4px;
111	  cursor: pointer;
112	  font-size: 0.8rem;
113	}
114	
115	.modal-delete:hover {
116	  background: #c0392b;
117	  color: #fff;
118	}
119	
120	.modal-delete-confirm {
121	  margin-top: 1rem;
122	  padding: 0.75rem;
123	  background: #fff5f5;
124	  border-radius: 6px;
125	  border: 1px solid #f5c6cb;
126	}
127	
128	/* Comments */
129	.modal-comments {
130	  margin-top: 1.25rem;
131	  border-top: 1px solid #eee;
132	  padding-top: 1rem;
133	}
134	
135	.modal-comments-heading {
136	  font-size: 0.9rem;
137	  font-weight: 600;
138	  margin-bottom: 0.5rem;
139	  color: #444;
140	}
141	
142	.modal-comments-list {
143	  list-style: none;
144	  padding: 0;
145	  margin: 0;
146	  display: flex;
147	  flex-direction: column;
148	  gap: 0.75rem;
149	}
150	
151	.modal-comment {
152	  font-size: 0.8rem;
153	}
154	
155	.modal-comment-meta {
156	  display: flex;
157	  gap: 0.5rem;
158	  color: #777;
159	  margin-bottom: 0.2rem;
160	}
161	
162	.modal-comment-author {
163	  font-weight: 600;
164	}
165	
166	.modal-comment-time {
167	  font-size: 0.75rem;
168	}
169	
170	.modal-comment-content {
171	  color: #333;
172	}
173	
174	.modal-no-comments {
175	  font-size: 0.8rem;
176	  color: #999;
177	  font-style: italic;
178	}
179	
180	/* Mobile bottom sheet */
181	@media (max-width: 600px) {
182	  .modal-content {
183	    max-width: 100%;
184	    width: 100%;
185	    min-height: 60vh;
186	    border-radius: 12px 12px 0 0;
187	    position: fixed;
188	    bottom: 0;
189	    padding: 1.25rem;
190	  }
191	}
